(function () {
    'use strict';
    var STORAGE_KEY = 'toolexa_dashboard_v1';
    var LEGACY_SEARCH_KEY = 'toolexa_recent_searches';
    var MAX_RECENT = 20;
    function defaults() {
        return {
            version: 1,
            favorites: {tools: [], articles: [], comparisons: []},
            pinnedTools: [],
            recent: {tools: [], articles: [], comparisons: [], searches: []},
            activity: {tools: [], articles: [], comparisons: []},
            collections: [],
            continueReading: null,
            updatedAt: new Date().toISOString()
        };
    }
    function text(value, limit) {
        return String(value == null ? '' : value).replace(/[\u0000-\u001f]/g, ' ').trim().slice(0, limit || 300);
    }
    function safeUrl(value) {
        try {
            var parsed = new URL(String(value || ''), window.location.origin);
            return parsed.origin === window.location.origin ? parsed.pathname + parsed.search + parsed.hash : '/';
        } catch (error) {
            return '/';
        }
    }
    function cleanItem(item, forcedType) {
        if (!item || typeof item !== 'object') return null;
        var type = forcedType || text(item.type, 20);
        if (['tool', 'article', 'comparison'].indexOf(type) < 0) return null;
        var slug = text(item.slug, 160);
        var title = text(item.title, 220);
        if (!slug || !title) return null;
        return {
            type: type,
            slug: slug,
            title: title,
            url: safeUrl(item.url),
            icon: text(item.icon || (type === 'article' ? 'BLOG' : type === 'comparison' ? 'VS' : 'TOOL'), 12),
            category: text(item.category || type, 100),
            description: text(item.description, 400),
            visitedAt: text(item.visitedAt || new Date().toISOString(), 40),
            progress: Math.max(0, Math.min(100, Number(item.progress) || 0))
        };
    }
    function cleanItems(items, type, max) {
        if (!Array.isArray(items)) return [];
        var seen = {};
        return items.map(function (item) { return cleanItem(item, type); }).filter(function (item) {
            if (!item || seen[item.slug]) return false;
            seen[item.slug] = true;
            return true;
        }).slice(0, max || 10000);
    }
    function normalize(raw) {
        var base = defaults();
        raw = raw && typeof raw === 'object' ? raw : {};
        base.favorites.tools = cleanItems(raw.favorites && raw.favorites.tools, 'tool');
        base.favorites.articles = cleanItems(raw.favorites && raw.favorites.articles, 'article');
        base.favorites.comparisons = cleanItems(raw.favorites && raw.favorites.comparisons, 'comparison');
        base.pinnedTools = cleanItems(raw.pinnedTools, 'tool');
        base.recent.tools = cleanItems(raw.recent && raw.recent.tools, 'tool', MAX_RECENT);
        base.recent.articles = cleanItems(raw.recent && raw.recent.articles, 'article', MAX_RECENT);
        base.recent.comparisons = cleanItems(raw.recent && raw.recent.comparisons, 'comparison', MAX_RECENT);
        base.recent.searches = Array.isArray(raw.recent && raw.recent.searches) ? raw.recent.searches.map(function (item) { return text(item, 100); }).filter(Boolean).filter(function (item, index, all) { return all.indexOf(item) === index; }).slice(0, MAX_RECENT) : [];
        base.activity.tools = Array.isArray(raw.activity && raw.activity.tools) ? raw.activity.tools.map(function (item) { return text(item, 160); }).filter(Boolean).filter(function (item, index, all) { return all.indexOf(item) === index; }) : [];
        base.activity.articles = Array.isArray(raw.activity && raw.activity.articles) ? raw.activity.articles.map(function (item) { return text(item, 160); }).filter(Boolean).filter(function (item, index, all) { return all.indexOf(item) === index; }) : [];
        base.activity.comparisons = Array.isArray(raw.activity && raw.activity.comparisons) ? raw.activity.comparisons.map(function (item) { return text(item, 160); }).filter(Boolean).filter(function (item, index, all) { return all.indexOf(item) === index; }) : [];
        base.collections = Array.isArray(raw.collections) ? raw.collections.map(function (collection) {
            return {id: text(collection.id || ('collection-' + Date.now()), 100), name: text(collection.name, 60), items: cleanItems(collection.items)};
        }).filter(function (collection) { return collection.name; }) : [];
        base.continueReading = cleanItem(raw.continueReading, 'article');
        base.updatedAt = text(raw.updatedAt || new Date().toISOString(), 40);
        return base;
    }
    function read() {
        try { return normalize(JSON.parse(window.localStorage.getItem(STORAGE_KEY) || 'null')); }
        catch (error) { return defaults(); }
    }
    function write(state) {
        state = normalize(state);
        state.updatedAt = new Date().toISOString();
        try {
            window.localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
            document.dispatchEvent(new CustomEvent('toolexa:dashboard-change', {detail: state}));
        } catch (error) {}
        return state;
    }
    function groupFor(type) {
        return type === 'tool' ? 'tools' : type === 'article' ? 'articles' : 'comparisons';
    }
    function upsertFirst(items, item, max) {
        return [item].concat(items.filter(function (current) { return current.slug !== item.slug; })).slice(0, max || 10000);
    }
    var store = {
        read: read,
        write: write,
        reset: function () { try { window.localStorage.removeItem(STORAGE_KEY); window.localStorage.removeItem(LEGACY_SEARCH_KEY); } catch (error) {} return write(defaults()); },
        track: function (item) {
            item = cleanItem(item);
            if (!item) return read();
            item.visitedAt = new Date().toISOString();
            var state = read();
            var group = groupFor(item.type);
            state.recent[group] = upsertFirst(state.recent[group], item, MAX_RECENT);
            if (state.activity[group].indexOf(item.slug) < 0) state.activity[group].push(item.slug);
            if (item.type === 'article') state.continueReading = item;
            return write(state);
        },
        isFavorite: function (type, slug) { return read().favorites[groupFor(type)].some(function (item) { return item.slug === slug; }); },
        toggleFavorite: function (item) {
            item = cleanItem(item);
            if (!item) return false;
            var state = read();
            var group = groupFor(item.type);
            var exists = state.favorites[group].some(function (current) { return current.slug === item.slug; });
            state.favorites[group] = exists ? state.favorites[group].filter(function (current) { return current.slug !== item.slug; }) : upsertFirst(state.favorites[group], item);
            write(state);
            return !exists;
        },
        isPinned: function (slug) { return read().pinnedTools.some(function (item) { return item.slug === slug; }); },
        togglePin: function (item) {
            item = cleanItem(item, 'tool');
            if (!item) return false;
            var state = read();
            var exists = state.pinnedTools.some(function (current) { return current.slug === item.slug; });
            state.pinnedTools = exists ? state.pinnedTools.filter(function (current) { return current.slug !== item.slug; }) : upsertFirst(state.pinnedTools, item);
            write(state);
            return !exists;
        },
        addRecentSearch: function (query) {
            query = text(query, 100);
            if (!query) return;
            var state = read();
            state.recent.searches = [query].concat(state.recent.searches.filter(function (item) { return item.toLowerCase() !== query.toLowerCase(); })).slice(0, MAX_RECENT);
            write(state);
        },
        getRecentSearches: function () {
            var searches = read().recent.searches;
            if (!searches.length) {
                try { searches = JSON.parse(window.localStorage.getItem(LEGACY_SEARCH_KEY) || '[]').slice(0, MAX_RECENT); } catch (error) { searches = []; }
            }
            return searches;
        },
        updateReading: function (item, progress) {
            item = cleanItem(item, 'article');
            if (!item) return;
            item.progress = Math.max(0, Math.min(100, Math.round(progress)));
            var state = read();
            state.continueReading = item;
            state.recent.articles = upsertFirst(state.recent.articles, item, MAX_RECENT);
            write(state);
        },
        createCollection: function (name) {
            name = text(name, 60);
            if (!name) return;
            var state = read();
            state.collections.push({id: 'collection-' + Date.now() + '-' + Math.random().toString(36).slice(2, 7), name: name, items: []});
            write(state);
        },
        deleteCollection: function (id) { var state = read(); state.collections = state.collections.filter(function (item) { return item.id !== id; }); write(state); },
        addToCollection: function (id, item) {
            item = cleanItem(item);
            if (!item) return;
            var state = read();
            state.collections = state.collections.map(function (collection) { if (collection.id === id) collection.items = upsertFirst(collection.items, item); return collection; });
            write(state);
        },
        removeFromCollection: function (id, slug) { var state = read(); state.collections = state.collections.map(function (collection) { if (collection.id === id) collection.items = collection.items.filter(function (item) { return item.slug !== slug; }); return collection; }); write(state); },
        importData: function (raw) { return write(normalize(raw)); },
        exportData: function () { return JSON.stringify(read(), null, 2); }
    };
    window.ToolexaStorage = store;
    function parsePageItem() {
        var raw = document.body.getAttribute('data-dashboard-item');
        if (!raw) return null;
        try { return cleanItem(JSON.parse(raw)); } catch (error) { return null; }
    }
    var pageItem = parsePageItem();
    if (pageItem) {
        store.track(pageItem);
        var hero = document.querySelector('.tool-hero');
        if (hero) {
            var actions = document.createElement('div');
            var favorite = document.createElement('button');
            actions.className = 'dashboard-page-actions';
            favorite.type = 'button';
            favorite.className = 'btn btn-sm';
            function updateFavorite() { favorite.textContent = store.isFavorite(pageItem.type, pageItem.slug) ? '★ Remove Favorite' : '☆ Add Favorite'; }
            favorite.addEventListener('click', function () { store.toggleFavorite(pageItem); updateFavorite(); });
            updateFavorite();
            actions.appendChild(favorite);
            if (pageItem.type === 'tool') {
                var workspace = document.createElement('a');
                workspace.className = 'btn btn-sm';
                workspace.href = (document.querySelector('meta[name="workspace-url"]') || {}).content || '/workspace?add=' + encodeURIComponent(pageItem.slug);
                workspace.textContent = 'Open in Workspace';
                actions.appendChild(workspace);
                var pin = document.createElement('button');
                pin.type = 'button';
                pin.className = 'btn btn-sm';
                function updatePin() { pin.textContent = store.isPinned(pageItem.slug) ? 'Unpin Tool' : 'Pin Tool'; }
                pin.addEventListener('click', function () { store.togglePin(pageItem); updatePin(); });
                updatePin();
                actions.appendChild(pin);
            }
            hero.appendChild(actions);
        }
        if (pageItem.type === 'article') {
            var readingTimer = null;
            function saveReadingProgress() {
                var height = Math.max(1, document.documentElement.scrollHeight - window.innerHeight);
                store.updateReading(pageItem, (window.scrollY / height) * 100);
            }
            window.addEventListener('scroll', function () { window.clearTimeout(readingTimer); readingTimer = window.setTimeout(saveReadingProgress, 400); }, {passive: true});
            if (new URL(window.location.href).searchParams.get('resume') === '1') {
                var saved = store.read().continueReading;
                if (saved && saved.slug === pageItem.slug) window.setTimeout(function () { window.scrollTo({top: (document.documentElement.scrollHeight - window.innerHeight) * saved.progress / 100, behavior: 'smooth'}); }, 250);
            }
        }
    }
    function initializeDashboard(root) {
        var catalogNode = root.querySelector('[data-dashboard-catalog]');
        var catalog = [];
        try { catalog = JSON.parse(catalogNode.textContent); } catch (error) {}
        function empty(container, message) {
            var p = document.createElement('p'); p.className = 'dashboard-empty'; p.textContent = message; container.appendChild(p);
        }
        function itemCard(item, options) {
            options = options || {};
            var card = document.createElement('article');
            var link = document.createElement('a');
            var icon = document.createElement('span');
            var body = document.createElement('span');
            var title = document.createElement('strong');
            var meta = document.createElement('small');
            card.className = options.compact ? 'dashboard-list-card' : 'dashboard-item-card';
            link.href = safeUrl(item.url) + (options.resume ? (safeUrl(item.url).indexOf('?') >= 0 ? '&resume=1' : '?resume=1') : '');
            icon.className = 'tool-icon'; icon.textContent = item.icon;
            body.className = 'dashboard-item-body'; title.textContent = item.title; meta.textContent = item.category;
            body.append(title, meta); link.append(icon, body); card.appendChild(link);
            if (item.type === 'tool') {
                var workspace = document.createElement('a'); workspace.className = 'dashboard-workspace-link';
                workspace.href = '/workspace?add=' + encodeURIComponent(item.slug); workspace.textContent = 'Workspace';
                card.appendChild(workspace);
            }
            if (options.progress != null) {
                var progress = document.createElement('div'); var bar = document.createElement('span'); progress.className = 'dashboard-reading-progress'; bar.style.width = options.progress + '%'; progress.appendChild(bar); card.appendChild(progress);
            }
            if (options.remove) {
                var remove = document.createElement('button'); remove.type = 'button'; remove.textContent = 'Remove'; remove.setAttribute('aria-label', 'Remove ' + item.title); remove.addEventListener('click', options.remove); card.appendChild(remove);
            }
            return card;
        }
        function renderList(selector, items, message, optionsFactory) {
            var container = root.querySelector(selector); container.innerHTML = '';
            if (!items.length) { empty(container, message); return; }
            items.forEach(function (item) { container.appendChild(itemCard(item, optionsFactory ? optionsFactory(item) : {})); });
        }
        function render() {
            var state = store.read();
            var stats = root.querySelector('[data-dashboard-stats]'); stats.innerHTML = '';
            [['Tools Used', state.activity.tools.length], ['Articles Read', state.activity.articles.length], ['Comparisons Viewed', state.activity.comparisons.length], ['Favorites', state.favorites.tools.length + state.favorites.articles.length + state.favorites.comparisons.length]].forEach(function (stat) {
                var card = document.createElement('article'); var strong = document.createElement('strong'); var span = document.createElement('span'); strong.textContent = stat[1]; span.textContent = stat[0]; card.append(strong, span); stats.appendChild(card);
            });
            renderList('[data-dashboard-pinned]', state.pinnedTools, 'Pin a tool from any tool page to keep it here.', function (item) { return {remove: function () { store.togglePin(item); }}; });
            renderList('[data-dashboard-recent-tools]', state.recent.tools, 'Your recently opened tools will appear here.');
            renderList('[data-dashboard-favorite-tools]', state.favorites.tools, 'No favorite tools yet.', function (item) { return {compact: true, remove: function () { store.toggleFavorite(item); }}; });
            renderList('[data-dashboard-favorite-articles]', state.favorites.articles, 'No favorite articles yet.', function (item) { return {compact: true, remove: function () { store.toggleFavorite(item); }}; });
            renderList('[data-dashboard-favorite-comparisons]', state.favorites.comparisons, 'No favorite comparisons yet.', function (item) { return {compact: true, remove: function () { store.toggleFavorite(item); }}; });
            var reading = root.querySelector('[data-dashboard-continue-reading]'); reading.innerHTML = '';
            if (state.continueReading) reading.appendChild(itemCard(state.continueReading, {resume: true, progress: state.continueReading.progress})); else empty(reading, 'Open an article and your reading progress will appear here.');
            var searches = root.querySelector('[data-dashboard-searches]'); searches.innerHTML = '';
            if (!state.recent.searches.length) empty(searches, 'Your latest searches will appear here.');
            state.recent.searches.forEach(function (query) { var link = document.createElement('a'); link.href = '/search?q=' + encodeURIComponent(query); link.textContent = query; searches.appendChild(link); });
            renderCollections(state);
        }
        function renderCollections(state) {
            var wrap = root.querySelector('[data-dashboard-collections]'); wrap.innerHTML = '';
            if (!state.collections.length) { empty(wrap, 'Create a collection such as Tax Tools, College Tools or Developer Tools.'); return; }
            state.collections.forEach(function (collection) {
                var card = document.createElement('article'); var head = document.createElement('header'); var title = document.createElement('h3'); var del = document.createElement('button');
                card.className = 'dashboard-collection-card'; title.textContent = collection.name; del.type = 'button'; del.textContent = 'Delete'; del.addEventListener('click', function () { if (window.confirm('Delete the collection "' + collection.name + '"?')) store.deleteCollection(collection.id); }); head.append(title, del); card.appendChild(head);
                var form = document.createElement('form'); var select = document.createElement('select'); var add = document.createElement('button'); select.className = 'form-control'; add.className = 'btn btn-sm'; add.type = 'submit'; add.textContent = 'Add Tool';
                var placeholder = document.createElement('option'); placeholder.value = ''; placeholder.textContent = 'Choose a tool'; select.appendChild(placeholder);
                catalog.forEach(function (item, index) { var option = document.createElement('option'); option.value = String(index); option.textContent = item.title; select.appendChild(option); });
                form.append(select, add); form.addEventListener('submit', function (event) { event.preventDefault(); if (select.value !== '') store.addToCollection(collection.id, catalog[Number(select.value)]); }); card.appendChild(form);
                var list = document.createElement('div'); list.className = 'dashboard-list'; if (!collection.items.length) empty(list, 'No tools in this collection yet.');
                collection.items.forEach(function (item) { list.appendChild(itemCard(item, {compact: true, remove: function () { store.removeFromCollection(collection.id, item.slug); }})); }); card.appendChild(list); wrap.appendChild(card);
            });
        }
        root.querySelector('[data-collection-form]').addEventListener('submit', function (event) { event.preventDefault(); var input = event.currentTarget.querySelector('input'); store.createCollection(input.value); input.value = ''; });
        root.querySelector('[data-dashboard-export]').addEventListener('click', function () { var blob = new Blob([store.exportData()], {type: 'application/json'}); var url = URL.createObjectURL(blob); var link = document.createElement('a'); link.href = url; link.download = 'toolexa-dashboard-backup.json'; document.body.appendChild(link); link.click(); link.remove(); URL.revokeObjectURL(url); });
        root.querySelector('[data-dashboard-import]').addEventListener('change', function (event) { var file = event.target.files && event.target.files[0]; if (!file) return; var reader = new FileReader(); reader.onload = function () { var status = root.querySelector('[data-dashboard-data-status]'); try { store.importData(JSON.parse(reader.result)); status.textContent = 'Dashboard restored successfully.'; } catch (error) { status.textContent = 'This file is not a valid Toolexa dashboard backup.'; } }; reader.readAsText(file); event.target.value = ''; });
        root.querySelector('[data-dashboard-reset]').addEventListener('click', function () { if (window.confirm('Clear all Toolexa favorites, history, pins and collections on this device?')) { store.reset(); root.querySelector('[data-dashboard-data-status]').textContent = 'Dashboard data cleared.'; } });
        document.addEventListener('toolexa:dashboard-change', render);
        render();
    }
    document.querySelectorAll('[data-personal-dashboard]').forEach(initializeDashboard);
}());
